window.HK_LC8 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["He is putting clothes into a washer.", "He is wiping a floor.", "He is cleaning a sink.", "He is taking apart a machine."], "optko": ["그는 세탁기에 옷을 넣고 있다.", "그는 바닥을 닦고 있다.", "그는 싱크대를 청소하고 있다.", "그는 기계를 분해하고 있다."], "ans": 3, "audio": "Test08_01.mp3", "img": "hk_t8_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["They're leaning on a railing.", "They're boarding a boat.", "They're looking at each other.", "They're passing by a gate."], "optko": ["그들은 난간에 기대어 있다.", "그들은 배에 탑승하고 있다.", "그들은 서로를 바라보고 있다.", "그들은 문 옆을 지나가고 있다."], "ans": 0, "audio": "Test08_02.mp3", "img": "hk_t8_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["They are standing in front of easels.", "They are having a discussion.", "They are hanging up posters.", "They are watching an artist paint a picture."], "optko": ["그들은 이젤 앞에 서 있다.", "그들은 토론을 하고 있다.", "그들은 포스터를 매달고 있다.", "그들은 화가가 그림 그리는 것을 보고 있다."], "ans": 0, "audio": "Test08_03.mp3", "img": "hk_t8_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["Leaves are being gathered.", "Some sticks have been put into a pile.", "A man is warming his hands.", "A man is enjoying a beautiful view."], "optko": ["나뭇잎들이 모아지고 있다.", "나뭇가지들이 한 더미로 쌓여 있다.", "한 남자가 그의 손을 데우고 있다.", "한 남자가 아름다운 경치를 즐기고 있다."], "ans": 1, "audio": "Test08_04.mp3", "img": "hk_t8_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["The doors of a barn have been shut.", "A tractor has been stored in a garage.", "Some animals are grazing on a farm.", "A field is being planted by workers."], "optko": ["창고의 문이 닫혀 있다.", "트랙터가 차고 안에 보관되어 있다.", "몇몇 동물들이 농장에서 풀을 뜯고 있다.", "밭이 작업자들에 의해 경작되고 있다."], "ans": 0, "audio": "Test08_05.mp3", "img": "hk_t8_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Suitcases are being loaded onto an aircraft.", "A man is leaning forward.", "A man is sitting in a waiting area.", "A plane is landing at an airport."], "optko": ["여행 가방들이 비행기에 실리고 있다.", "한 남자가 앞으로 숙이고 있다.", "한 남자가 대합실에 앉아 있다.", "비행기가 공항에 착륙하고 있다."], "ans": 2, "audio": "Test08_06.mp3", "img": "hk_t8_q6.jpg"}, {"n": 7, "part": 2, "q": "How do you usually book your vacations?", "qko": "보통 어떻게 휴가를 예약하나요?", "opts": ["I'm open to all of those destinations.", "Here's a copy of the book.", "I use a travel agent."], "optko": ["저는 모든 목적지들이 괜찮아요.", "여기 그 책이 한 부 있어요.", "저는 여행사를 이용해요."], "ans": 2, "audio": "Test08_07.mp3"}, {"n": 8, "part": 2, "q": "The bakery around the corner extended its hours.", "qko": "길모퉁이에 있는 제과점이 영업 시간을 연장했어요.", "opts": ["Some loaves of whole wheat bread.", "Yeah, I saw the advertisement.", "Around noon, I think."], "optko": ["통밀빵 약간이요.", "네, 저는 그 광고를 봤어요.", "제 생각으로는 정오쯤이에요."], "ans": 1, "audio": "Test08_08.mp3"}, {"n": 9, "part": 2, "q": "Does this dress shirt also come in white?", "qko": "이 와이셔츠는 흰색으로도 들어오나요?", "opts": ["I'll have to check.", "Fold down the collar, too.", "The black jeans look trendy."], "optko": ["확인해봐야 할 것 같아요.", "옷깃도 접으세요.", "검은색 청바지가 최신 유행처럼 보이네요."], "ans": 0, "audio": "Test08_09.mp3"}, {"n": 10, "part": 2, "q": "Will my radio interview last for very long?", "qko": "저의 라디오 인터뷰가 매우 오랫동안 계속될까요?", "opts": ["Toward the end of the row.", "No more than 15 minutes.", "Oh, we talked about numerous issues."], "optko": ["열의 끝쪽으로요.", "15분 이상 걸리지 않아요.", "아, 저희는 많은 문제들에 대해 이야기했어요."], "ans": 1, "audio": "Test08_10.mp3"}, {"n": 11, "part": 2, "q": "Where did you find the extra training manuals?", "qko": "여분의 교육 매뉴얼을 어디에서 찾았나요?", "opts": ["No, I didn't.", "Refer to page 34 to see it.", "In the supply closet."], "optko": ["아니요, 하지 않았어요.", "그것을 보시려면 34페이지를 참고하세요.", "비품 창고에서요."], "ans": 2, "audio": "Test08_11.mp3"}, {"n": 12, "part": 2, "q": "Who typically manages Mr. Harper's schedule?", "qko": "Mr. Harper의 일정을 누가 보통 관리하나요?", "opts": ["His personal assistant, Ben.", "Sally usually shows up on time.", "Changes to the program schedule."], "optko": ["그의 개인 비서인 Ben이요.", "Sally는 보통 제시간에 나타나요.", "프로그램 일정의 변경 사항이요."], "ans": 0, "audio": "Test08_12.mp3"}, {"n": 13, "part": 2, "q": "Who should I speak to about the proposal, Ms. Neilson or Mr. Shears?", "qko": "제가 그 제안에 대해 Ms. Neilson에게 이야기해야 하나요, 아니면 Mr. Shears에게 이야기해야 하나요?", "opts": ["You shouldn't change the password.", "Have you written your acceptance speech?", "You should speak to both of them."], "optko": ["당신은 비밀번호를 변경하선 안 돼요.", "당신의 수락 연설을 작성하셨나요?", "당신은 그들 둘 다에게 이야기해야 해요."], "ans": 2, "audio": "Test08_13.mp3"}, {"n": 14, "part": 2, "q": "When can I expect the package to arrive?", "qko": "소포가 언제 도착할 거라고 예상할 수 있을까요?", "opts": ["At the post office.", "Sometime next week.", "Because I sent it out yesterday."], "optko": ["우체국에서요.", "다음 주 중에요.", "제가 그것을 어제 보냈기 때문이에요."], "ans": 1, "audio": "Test08_14.mp3"}, {"n": 15, "part": 2, "q": "The financial advisor hasn't dropped by yet, has he?", "qko": "재정 고문이 아직 들르지 않았죠, 그렇죠?", "opts": ["No, the bank charges a monthly fee.", "He's visiting us next week.", "Thanks for your advice!"], "optko": ["아니요, 은행은 월별 요금을 부과해요.", "그는 다음 주에 우리를 방문할 예정이에요.", "조언 감사해요!"], "ans": 1, "audio": "Test08_15.mp3"}, {"n": 16, "part": 2, "q": "Could you give Ms. Delano directions to the train station?", "qko": "Ms. Delano에게 기차역까지 길 안내를 해주시겠어요?", "opts": ["Sure, where is she now?", "The director's approval.", "It's a round-trip ticket."], "optko": ["물론이죠, 그녀는 지금 어디에 있나요?", "관리자의 승인이요.", "왕복 티켓이에요."], "ans": 0, "audio": "Test08_16.mp3"}, {"n": 17, "part": 2, "q": "One of the ovens in the café needs to be fixed.", "qko": "카페의 오븐들 중 하나가 수리되어야 해요.", "opts": ["Apparently, the oven is available in silver.", "Both chefs are happy with the menu.", "Hopefully, a technician can come today."], "optko": ["보아하니, 그 오븐은 은색으로도 있어요.", "두 명의 요리사들 모두 메뉴에 만족스러워해요.", "바라건대, 기술자가 오늘 와주면 좋겠어요."], "ans": 2, "audio": "Test08_17.mp3"}, {"n": 18, "part": 2, "q": "You can represent the company at the employment fair, can't you?", "qko": "당신은 채용 박람회에서 회사를 대표해줄 수 있죠, 안 그런가요?", "opts": ["Employee evaluations went well.", "The company representative.", "I'm up for the challenge."], "optko": ["직원 평가는 잘 진행되었어요.", "회사 대표요.", "기꺼이 도전해볼게요."], "ans": 2, "audio": "Test08_18.mp3"}, {"n": 19, "part": 2, "q": "Why is Mr. Liu sending a memo to staff members?", "qko": "Mr. Liu가 왜 직원들에게 회람을 보내고 있나요?", "opts": ["Some of the original memos.", "I haven't been told the reason.", "Any worker can use it."], "optko": ["몇몇 원본 회람들이요.", "이유는 듣지 못했어요.", "어떤 직원이든 그것을 사용할 수 있어요."], "ans": 1, "audio": "Test08_19.mp3"}, {"n": 20, "part": 2, "q": "Our supervisor has offered to provide us with standing desks.", "qko": "우리의 관리자가 우리에게 입식 책상을 제공하겠다고 제안했어요.", "opts": ["Yes, the office needs better lighting.", "A drawer in my desk.", "I'm actually a fan of my current setup."], "optko": ["네, 사무실은 더 좋은 조명이 필요해요.", "제 책상의 서랍이요.", "저는 사실 현재의 설비가 좋아요."], "ans": 2, "audio": "Test08_20.mp3"}, {"n": 21, "part": 2, "q": "Would you like the order to be delivered to your front door?", "qko": "주문품을 당신의 현관으로 배달해드릴까요?", "opts": ["Yes, our hotel has vacancies.", "For the delivery person.", "That depends on when it arrives."], "optko": ["네, 저희 호텔은 빈방이 있어요.", "배달원을 위해서요.", "그것이 언제 도착하는지에 달려 있어요."], "ans": 2, "audio": "Test08_21.mp3"}, {"n": 22, "part": 2, "q": "How many cars did our dealership sell this week?", "qko": "우리 대리점이 이번 주에 자동차 몇 대를 판매했나요?", "opts": ["Records indicate a few dozen.", "Yes, it's on sale.", "My vehicle has excellent features."], "optko": ["기록이 수십 대라고 보여주네요.", "네, 그건 할인 중이에요.", "제 차량은 훌륭한 특색들이 있어요."], "ans": 0, "audio": "Test08_22.mp3"}, {"n": 23, "part": 2, "q": "Where should I place this box of cosmetics?", "qko": "이 화장품 박스를 어디에 놓아야 하나요?", "opts": ["A boxing match.", "I liked the makeup very much.", "There isn't any room here."], "optko": ["권투 시합이요.", "저는 그 화장이 정말 마음에 들었어요.", "여기에는 자리가 없어요."], "ans": 2, "audio": "Test08_23.mp3"}, {"n": 24, "part": 2, "q": "Which violin are you thinking about purchasing?", "qko": "당신은 어느 바이올린을 구매하려고 생각 중이신가요?", "opts": ["And some other musical instruments.", "The one in the case, most likely.", "I bought them online."], "optko": ["그리고 다른 악기들이요.", "아마도 저 상자에 들어 있는 것이요.", "저는 그것들을 온라인으로 구매했어요."], "ans": 1, "audio": "Test08_24.mp3"}, {"n": 25, "part": 2, "q": "Why don't we implement a summer internship program?", "qko": "여름 인턴십 프로그램을 실시하는 게 어때요?", "opts": ["Here are my spring travel plans.", "My internship starts next week.", "You should propose the idea to management."], "optko": ["여기 저의 봄 여행 계획들이 있어요.", "제 인턴십은 다음 주에 시작해요.", "당신은 그 의견을 경영진에게 제의해야 해요."], "ans": 2, "audio": "Test08_25.mp3"}, {"n": 26, "part": 2, "q": "Have Rebecca and James finished making graphs for the shareholders meeting?", "qko": "Rebecca와 James가 주주총회를 위한 그래프들을 만드는 것을 끝냈나요?", "opts": ["Only some of our stakeholders.", "To complete the entire lesson.", "I've got the graphs here."], "optko": ["우리의 주주들 중 일부만요.", "전체 수업을 끝내기 위해서요.", "여기 도표들을 받았어요."], "ans": 2, "audio": "Test08_26.mp3"}, {"n": 27, "part": 2, "q": "Why can't Marcus work until 7 P.M. on Friday?", "qko": "Marcus는 왜 금요일에 오후 7시까지 일할 수 없나요?", "opts": ["Yes, he's very talented.", "Due to a medical appointment.", "It's currently 1 o'clock."], "optko": ["네, 그는 매우 재능이 있어요.", "진료 예약 때문이에요.", "현재 1시예요."], "ans": 1, "audio": "Test08_27.mp3"}, {"n": 28, "part": 2, "q": "Is this project going to be discussed in person or via an online conference?", "qko": "이 프로젝트는 직접 논의될 것인가요, 아니면 온라인 회의를 통해 논의될 것인가요?", "opts": ["The details haven't been announced.", "I assume you've visited the Web site before.", "What did they end up talking about?"], "optko": ["세부 사항들은 공지되지 않았어요.", "당신이 이전에 웹사이트를 방문한 적이 있는 것 같군요.", "그들이 결국 무엇에 대해 이야기했나요?"], "ans": 0, "audio": "Test08_28.mp3"}, {"n": 29, "part": 2, "q": "Should I finish typing the staffing report for you?", "qko": "제가 직원 채용 보고서를 입력하는 것을 끝내야 하나요?", "opts": ["No, I'd rather do it myself.", "I like those types of dishes.", "Because of staffing problems."], "optko": ["아니요, 제가 직접 하는 편이 좋겠어요.", "저는 그런 종류의 음식들이 좋아요.", "직원 채용에 관한 문제들 때문이에요."], "ans": 0, "audio": "Test08_29.mp3"}, {"n": 30, "part": 2, "q": "Isn't the championship game tonight?", "qko": "결승전이 오늘 밤 아닌가요?", "opts": ["It's going to be a great match.", "The delivery will arrive this evening.", "No, I prefer playing soccer."], "optko": ["그것은 대단한 시합이 될 거예요.", "배송품은 오늘 저녁에 도착할 거예요.", "아니요, 저는 축구하는 것을 선호해요."], "ans": 0, "audio": "Test08_30.mp3"}, {"n": 31, "part": 2, "q": "When will the press statement be released to the local news media?", "qko": "언론 성명서가 지역 뉴스 매체에 언제 공개될 예정인가요?", "opts": ["I work at a regional newspaper.", "Not since the journalist called.", "Marcie said it will be a bit delayed."], "optko": ["저는 지역 신문사에서 일해요.", "기자가 전화한 이후로는 아니에요.", "Marcie가 그것이 약간 지연될 거라고 말했어요."], "ans": 2, "audio": "Test08_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Ca", "audio": "Test08_32-34.mp3", "qs": [{"n": 32, "q": "What does the woman want to promote?", "opts": ["A Web site", "Some footwear", "A local charity", "Some new policies"], "ans": 1, "ko": "여자는 무엇을 홍보하고 싶어 하는가?"}, {"n": 33, "q": "What is mentioned about the radio commercials?", "opts": ["They were not approved by a director.", "They featured a popular celebrity.", "They were expensive to produce.", "They did not reach the right listeners."], "ans": 3, "ko": "라디오 광고에 관해 무엇이 언급되는가?"}, {"n": 34, "q": "What does the man suggest?", "opts": ["Uploading an attachment", "Seeking another opinion", "Preparing for a future launch", "Rearranging some displays"], "ans": 1, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "The sneakers our company released last month have been underperforming. I think we should put together a marketing campaign to raise awareness about them.", "ko": "지난달에 우리 회사가 출시한 운동화가 실적을 못 내고 있어요. 저는 우리가 그것들에 대한 인식을 높이기 위해 마케팅 캠페인을 만들어야 한다고 생각해요."}, {"sp": "M", "en": "Yeah, that makes sense. However, I don't think we should use radio commercials like we did for our previous launch. They didn't effectively reach our target audience.", "ko": "맞아요, 이해가 되네요. 하지만, 이전 출시 때 했던 것처럼 우리가 라디오 광고를 이용해야 한다고는 생각하지 않아요. 그것들은 우리의 광고 대상에게 효과적으로 도달하지 못했어요."}, {"sp": "W", "en": "Actually, I think a social media campaign would be best. We can create banner advertisements and display them through online posts.", "ko": "사실, 저는 소셜 미디어 캠페인이 가장 좋을 거라고 생각해요. 우리는 배너 광고들을 만들어서 그것들을 온라인 게시물을 통해 보여줄 수 있어요."}, {"sp": "M", "en": "Good idea. But let's e-mail our director to get her input before making a final decision.", "ko": "좋은 생각이에요. 하지만 최종 결정을 내리기 전에 우리의 관리자에게 이메일을 보내 그녀의 조언을 얻도록 해요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test08_35-37.mp3", "qs": [{"n": 35, "q": "What are the speakers mainly discussing?", "opts": ["A building remodeling", "A computer program", "An upcoming event", "A weekly schedule"], "ans": 2, "ko": "화자들은 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 36, "q": "Why is the man concerned?", "opts": ["Some information does not match.", "A Web site is difficult to navigate.", "A document has been lost.", "Some library staff have not arrived."], "ans": 0, "ko": "남자는 왜 걱정을 하는가?"}, {"n": 37, "q": "What does the man say he will do next?", "opts": ["Call a caterer", "Notify a supervisor", "Visit a library", "Organize some files"], "ans": 1, "ko": "남자는 다음에 무엇을 할 거라고 말하는가?"}], "script": [{"sp": "W", "en": "William, have you reviewed the invitation template I created for Richmond Library's reopening party?", "ko": "William, Richmond 도서관 재개관 파티를 위해 제가 제작한 초대장 견본을 살펴 보셨나요?"}, {"sp": "M", "en": "Yes, but I noticed an issue. You wrote that the gathering will be held next Friday. However, the library's Web site says it's taking place next Thursday.", "ko": "네, 그런데 문제를 발견했어요. 당신은 모임이 다음 주 금요일에 열릴 것이라고 썼어요. 하지만, 도서관의 웹사이트에는 이것이 다음 주 목요일에 열릴 것이라고 되어 있어요."}, {"sp": "W", "en": "Well, when you were out sick yesterday, our team met with the head librarian. And she mentioned it will have to take place on Friday instead . . . uh . . . due to a scheduling conflict.", "ko": "음, 당신이 어제 아파서 결근했을 때, 우리 팀은 수석 사서를 만났어요. 그리고 그녀는 이것이 대신 금요일에 개최되어야 할 거라고 말했어요… 어… 일정이 겹쳐서요."}, {"sp": "M", "en": "OK. In that case, the Web site will have to be updated. I'll call the head librarian now and tell her to do so.", "ko": "알겠어요. 그런 경우에는, 웹사이트가 업데이트되어야겠네요. 제가 수석 사서에게 지금 전화해서 그렇게 하도록 말할게요."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Ca", "audio": "Test08_38-40.mp3", "qs": [{"n": 38, "q": "Who most likely is the woman?", "opts": ["A delivery person", "A shop owner", "A tourist", "A travel agent"], "ans": 2, "ko": "여자는 누구인 것 같은가?"}, {"n": 39, "q": "What does the man offer to do?", "opts": ["Provide a map", "Cover a shipping fee", "Package an item", "Recommend a restaurant"], "ans": 2, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}, {"n": 40, "q": "What does the man say about loyalty points?", "opts": ["They can be used as payment.", "They expire within one year.", "They are earned online only.", "They work at multiple stores."], "ans": 0, "ko": "남자는 회원 포인트에 관해 무엇을 말하는가?"}], "script": [{"sp": "W", "en": "Excuse me. Does your shop offer international shipping services? I'd like to get this teapot. But I'm worried it might break in my suitcase on my flight back to Spain.", "ko": "실례합니다. 당신의 가게에서 국제 배송 서비스를 제공하나요? 저는 이 찻주전자를 사고 싶어요. 하지만 이것이 스페인으로 돌아가는 비행 중에 제 여행 가방 안에서 깨질까 봐 걱정돼요."}, {"sp": "M", "en": "We can't send items overseas, unfortunately. However, I can put the teapot in bubble wrap for you. That should protect it while you're traveling.", "ko": "안타깝게도, 저희는 물건들을 해외로 발송할 수 없어요. 하지만 찻주전자를 버블랩에 넣어드릴 수는 있어요. 그게 손님이 여행하시는 동안에 이걸 보호해줄 거예요."}, {"sp": "W", "en": "Wonderful . . . I love your store, by the way. I often travel to England and always stop in here.", "ko": "훌륭해요… 그건 그렇고, 저는 당신의 가게가 아주 마음에 들어요. 저는 영국으로 자주 여행오는데, 이곳에 항상 들러요."}, {"sp": "M", "en": "Thank you. Would you like a card for our loyalty program then? You can earn points with everything you buy and use them to pay for future purchases.", "ko": "감사해요. 그렇다면 저희의 회원 프로그램 카드를 드릴까요? 구매하신 모든 것에 대해 포인트를 받아 추후의 구매에 대한 비용을 지불하는 데 사용하실 수 있어요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "W1-Am / W2-Br / M-Ca", "audio": "Test08_41-43.mp3", "qs": [{"n": 41, "q": "Where most likely do the speakers work?", "opts": ["At a manufacturing plant", "At a shopping center", "At a government office", "At a photography studio"], "ans": 3, "ko": "화자들은 어디에서 일하는 것 같은가?"}, {"n": 42, "q": "What problem is mentioned?", "opts": ["Some software has errors.", "A complaint was made.", "Some shoots were canceled.", "A business is understaffed."], "ans": 1, "ko": "어떤 문제가 언급되는가?"}, {"n": 43, "q": "What will the man most likely do before noon?", "opts": ["Take additional pictures", "Respond to a message", "Edit some pictures", "Send out an invoice"], "ans": 2, "ko": "남자는 정오 이전에 무엇을 할 것 같은가?"}], "script": [{"sp": "W1", "en": "Ted and Megumi, the president of Norma Manufacturing just called. He's not pleased with the photos we recently took of his executive team.", "ko": "Ted와 Megumi, Norma 제조사의 사장이 방금 전화했어요. 그는 최근에 우리가 찍은 그의 경영진의 사진에 만족하지 않아요."}, {"sp": "W2", "en": "What's wrong with them?", "ko": "그것들에 무슨 문제가 있나요?"}, {"sp": "W1", "en": "He said shadows are cast on people's faces, which makes it difficult to make out their features.", "ko": "사람들의 얼굴에 그림자가 드리워져 있는데, 이것이 그들의 이목구비를 알아보기 어렵게 만든다고 그가 말했어요."}, {"sp": "M", "en": "Don't worry. I can fix that issue with our digital editing software. I can brighten up the foreground a bit more.", "ko": "걱정 마요. 제가 디지털 편집 소프트웨어로 그 문제를 해결할 수 있어요. 전경을 좀 더 환하게 할 수 있어요."}, {"sp": "W1", "en": "That's a relief! I thought we'd have to arrange another shoot. Um . . . I'm supposed to call the president's assistant this afternoon. So, Ted, how long will it take you to edit the photos?", "ko": "다행이네요! 저는 우리가 또 다른 사진 촬영을 준비해야 하는 줄 알았어요. 음… 저는 오늘 오후에 사장의 비서에게 전화하기로 되어 있어요. 그럼, Ted, 당신이 사진을 편집하는 데 얼마나 걸릴까요?"}, {"sp": "M", "en": "A couple of hours. I'll upload the files to our server before 12 P.M.", "ko": "한두 시간이요. 오후 12시 전에 우리 서버에 파일을 업로드할게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W-Am", "audio": "Test08_44-46.mp3", "qs": [{"n": 44, "q": "Why is the man calling?", "opts": ["To submit a payment", "To confirm some instructions", "To schedule a delivery", "To request a document"], "ans": 3, "ko": "남자는 왜 전화를 하고 있는가?"}, {"n": 45, "q": "According to the woman, what happened last month?", "opts": ["A notification was sent.", "A merger took place.", "An account was renewed.", "A sale was introduced."], "ans": 0, "ko": "여자에 따르면, 지난달에 무슨 일이 일어났는가?"}, {"n": 46, "q": "What will the man give the woman?", "opts": ["Some personal information", "Some customer feedback", "A discount code", "A business address"], "ans": 0, "ko": "남자는 여자에게 무엇을 줄 것인가?"}], "script": [{"sp": "M", "en": "Hello. My name is Miguel Hernandez. I'm calling because I haven't received my electricity bill in the mail this month. Could you please send it?", "ko": "안녕하세요. 제 이름은 Miguel Hernandez입니다. 이번 달에 전기 요금 청구서를 우편으로 받지 못해서 전화드립니다. 그것을 보내주실 수 있나요?"}, {"sp": "W", "en": "Let me review your account, Mr. Hernandez . . . Actually, it appears that you've signed up to receive paperless billing. You should have gotten an e-mail about the change last month. And your electronic bill was sent two days ago.", "ko": "제가 귀하의 계좌를 살펴보겠습니다, Mr. Hernandez… 사실, 귀하는 종이를 사용하지 않는 청구서 수신을 신청하신 것으로 보입니다. 변경 사항에 대한 이메일을 지난달에 받으셨어야 합니다. 그리고 귀하의 전기 요금 청구서는 이틀 전에 발송되었습니다."}, {"sp": "M", "en": "Is that so? Which e-mail address was the bill sent to?", "ko": "그래요? 청구서가 어느 이메일 주소로 발송되었나요?"}, {"sp": "W", "en": "The address is mhernandez3@myemail.com. You provided it when you first started using our service.", "ko": "주소는 mhernandez3@myemail.com입니다. 저희의 서비스를 처음 이용하기 시작하셨을 때 이것을 저희에게 제공해 주셨어요."}, {"sp": "M", "en": "Oh, I stopped using that account. I'll give you my new one now.", "ko": "아, 저는 그 계정 사용을 중단했어요. 지금 새로운 것을 드릴게요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "M-Au / W1-Br / W2-Am", "audio": "Test08_47-49.mp3", "qs": [{"n": 47, "q": "Why does the man want to update his kitchen?", "opts": ["Some appliances are outdated.", "A floor is unsafe.", "Some tiles have faded.", "A property is going to be sold."], "ans": 2, "ko": "남자는 왜 그의 부엌을 새롭게 하고 싶어 하는가?"}, {"n": 48, "q": "What does the man say about HomeRefresh?", "opts": ["Its services are expensive.", "Its contract is complicated.", "Its employees are friendly.", "Its location is inconvenient."], "ans": 0, "ko": "남자는 HomeRefresh사에 관해 무엇을 말하는가?"}, {"n": 49, "q": "What will probably happen next?", "opts": ["A budget will be discussed.", "A discount will be applied.", "An appointment will be arranged.", "A message will be sent."], "ans": 3, "ko": "다음에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "I want to replace the tiles on my kitchen floor since many of them have lost their color over time. Can either of you suggest a good flooring specialist?", "ko": "제 부엌 바닥의 타일들 다수가 시간이 지나면서 색이 바랬기 때문에 저는 그것들을 교체하고 싶어요. 두 분 중 누구라도 좋은 바닥재 전문가를 추천해 주실 수 있나요?"}, {"sp": "W1", "en": "Tanya, didn't you have the same work done last year?", "ko": "Tanya, 당신은 작년에 같은 작업을 하지 않았어요?"}, {"sp": "W2", "en": "I had carpeting installed in my living room. But the man I hired takes care of all types of flooring. His name is Frank, and his company is called HomeRefresh.", "ko": "저는 거실에 카펫을 설치했었어요. 하지만 제가 고용했던 사람은 모든 종류의 바닥재를 다뤄요. 그의 이름은 Frank이고, 그의 회사는 HomeRefresh사라고 해요."}, {"sp": "M", "en": "Actually, I already looked up HomeRefresh online, but I can't afford its high rates.", "ko": "사실, 이미 온라인으로 HomeRefresh사를 찾아보았는데, 저는 그것의 높은 요금을 감당할 형편이 안 돼요."}, {"sp": "W1", "en": "Well, my neighbor recently remodeled his kitchen. Why don't I text him right now to see which business he used? Maybe it will be a bit cheaper.", "ko": "음, 제 이웃이 최근에 그의 주방을 개조했어요. 그가 어떤 사업체를 이용했는지 알아보기 위해 제가 지금 바로 그에게 문자 메시지를 보내면 어때요? 아마 조금 더 저렴할 거예요."}, {"sp": "M", "en": "That would be very helpful. Thanks!", "ko": "그건 큰 도움이 될 거예요. 고마워요!"}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Ca", "audio": "Test08_50-52.mp3", "qs": [{"n": 50, "q": "What does the woman say about the Japanese clients?", "opts": ["They are coming for two nights.", "They are expecting to see a play.", "They will arrive this week.", "They will stay at a luxury hotel."], "ans": 2, "ko": "여자는 일본인 고객들에 관해 무엇을 말하는가?"}, {"n": 51, "q": "Why does the man say, \"They were supposed to be here until Thursday morning\"?", "opts": ["To explain a mistake", "To indicate disapproval", "To confirm a work schedule", "To provide corrected details"], "ans": 0, "ko": "남자는 왜 \"그들은 목요일 아침까지 이곳에 있기로 되어 있었잖아요\"라고 말하는가?"}, {"n": 52, "q": "What does the woman recommend?", "opts": ["Taking an earlier flight", "Apologizing to some visitors", "Rescheduling a reservation", "Giving away some tickets"], "ans": 3, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Dixon, have you settled on plans for when our Japanese clients visit New York City on this Wednesday?", "ko": "Dixon, 이번 주 수요일에 우리의 일본인 고객들이 뉴욕을 방문할 때를 위한 계획을 정했나요?"}, {"sp": "M", "en": "Yeah. I want to take them to see a play that night.", "ko": "네. 그날 밤 그들이 연극을 관람하실 수 있도록 모시고 싶어요."}, {"sp": "W", "en": "Will there be time for that? They have a flight at 10 P.M.", "ko": "그럴 시간이 있을까요? 그들은 오후 10시에 비행기를 타요."}, {"sp": "M", "en": "Oh . . . I forgot they have to leave a day earlier than originally planned. They were supposed to be here until Thursday morning. Unfortunately, I already bought the play tickets.", "ko": "아… 그들이 원래 계획했던 것보다 하루 일찍 떠나야 한다는 것을 잊었네요. 그들은 목요일 아침까지 이곳에 있기로 되어 있었잖아요. 안타깝게도, 저는 이미 연극 티켓을 샀어요."}, {"sp": "W", "en": "How about gifting them to Mr. Preston—our client from Central Developers? He mentioned in our recent project meeting that he's a big fan of performing arts.", "ko": "우리 고객인 Central Developers사의 Mr. Preston에게 그것들을 선물로 주는 것이 어때요? 그는 최근 우리의 프로젝트 회의에서 공연 예술의 열렬한 팬이라고 말했어요."}, {"sp": "M", "en": "Good idea. I'll make reservations at a fancy restaurant for Wednesday evening instead.", "ko": "좋은 생각이네요. 대신 수요일 저녁에 고급 레스토랑을 예약할게요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Cn", "audio": "Test08_53-55.mp3", "qs": [{"n": 53, "q": "According to the woman, what does Ms. Bailey need?", "opts": ["A conference agenda", "Electronic equipment", "An audio recording", "Presentation handouts"], "ans": 1, "ko": "여자에 따르면, Ms. Bailey가 필요한 것은 무엇인가?"}, {"n": 54, "q": "What does the woman mean when she says, \"I'm sure we can handle that\"?", "opts": ["A technician will be hired.", "An event will be successful.", "A presentation can be shortened.", "An expense can be covered."], "ans": 3, "ko": "여자는 \"우리가 그걸 처리할 수 있을 거라고 확신해요\"라고 말할 때 무엇을 의도하는가?"}, {"n": 55, "q": "What does the man say he must do?", "opts": ["Revise a request", "Download a document", "Tour an event hall", "Consult with a team"], "ans": 0, "ko": "남자는 무엇을 해야 한다고 말하는가?"}], "script": [{"sp": "W", "en": "I recently discovered that we'll need some audiovisual devices for Jennifer Bailey's presentation at the Green Energy Conference. Apparently, she's decided to play video clips with her talk.", "ko": "저는 그린 에너지 학회에서 Jennifer Bailey의 발표를 위해 우리가 시청각 장치가 필요할 거라는 걸 최근에 발견했어요. 듣자 하니, 그녀는 강연에서 동영상을 재생하기로 결정했다고 해요."}, {"sp": "M", "en": "That's fine, but there will be an extra charge for the technical team at the event hall to set up everything.", "ko": "괜찮아요. 하지만 모든 것을 설치하기 위해서는 행사장에서 기술팀에 추가 요금이 발생할 거예요."}, {"sp": "W", "en": "I just got out of a meeting with our budgeting committee, and I'm sure we can handle that.", "ko": "저는 방금 예산 위원회와의 회의에 갔다 왔는데, 우리가 그걸 처리할 수 있을 거라고 확신해요."}, {"sp": "M", "en": "Great. I just have to edit our booking request on the hall's Web page to reflect this new requirement.", "ko": "좋아요. 저는 그럼 이 새로운 요구 사항을 반영하기 위해 행사장의 웹페이지에서 예약 요청을 수정해야겠어요."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "W-Br / M-Au", "audio": "Test08_56-58.mp3", "qs": [{"n": 56, "q": "Where most likely is the conversation taking place?", "opts": ["At a consultancy headquarters", "At a conference venue", "At a retail store", "At a post office"], "ans": 2, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 57, "q": "What does the man ask the woman to do?", "opts": ["Move some items", "Lock a room", "Organize some supplies", "Place an order"], "ans": 3, "ko": "남자는 여자에게 무엇을 하라고 요청하는가?"}, {"n": 58, "q": "What is mentioned about the list?", "opts": ["It was recently thrown away.", "It has to be reprinted.", "It has been relocated.", "It has been updated."], "ans": 2, "ko": "목록에 관해 무엇이 언급되는가?"}], "script": [{"sp": "W", "en": "Mr. Wesley, here's the completed inventory report you wanted. Ah . . . our shop is running low on stationery goods, like notebooks and pens.", "ko": "Mr. Wesley, 당신이 원하신 완성된 재고 보고서가 여기 있어요. 아... 우리 가게는 수첩이나 펜 같은 문구 용품이 부족해요."}, {"sp": "M", "en": "OK. It seems that the free delivery service we offered in September helped us sell more of those items. Can you please order new stock by this weekend?", "ko": "알겠어요. 9월에 우리가 제공했던 무료 배송 서비스가 더 많은 상품을 판매하는 데 도움이 된 것 같네요. 이번 주 말까지 새로운 재고품을 주문해줄 수 있나요?"}, {"sp": "W", "en": "I was just about to do that. But I don't know what happened to the list of suppliers that used to be posted in the office.", "ko": "제가 막 그걸 하려던 참이었어요. 하지만 사무실에 게시되어 있던 공급 회사 목록에 무슨 일이 일어났는지 모르겠어요."}, {"sp": "M", "en": "Oh, sorry. It's locked in the top desk drawer because it contains confidential information. Let me grab a key for you to open that.", "ko": "아, 미안해요. 그것이 기밀 정보를 포함하고 있기 때문에 책상 맨 위 서랍 속에 잠가 두었어요. 그것을 열 수 있도록 제가 열쇠를 가져올게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "W-Am / M-Au", "audio": "Test08_59-61.mp3", "qs": [{"n": 59, "q": "Why is the woman calling?", "opts": ["To report a delay", "To inquire about a property", "To request a service", "To file a complaint"], "ans": 0, "ko": "여자는 왜 전화를 하고 있는가?"}, {"n": 60, "q": "According to the woman, what will happen this evening?", "opts": ["A vehicle will be purchased.", "Some repairs will be completed.", "A new worker will be trained.", "Some paint will be picked up."], "ans": 1, "ko": "여자에 따르면, 오늘 저녁에 무슨 일이 일어날 것인가?"}, {"n": 61, "q": "Who is Angela Dawson?", "opts": ["An office manager", "A professional painter", "An automotive mechanic", "An administrative assistant"], "ans": 3, "ko": "Angela Dawson은 누구인가?"}], "script": [{"sp": "W", "en": "Hello. This is Kelly McDermott from Sunshine Painters. We're scheduled to paint the outside of your realty office today. However, our truck just broke down, and we're unable to make it to your building this morning.", "ko": "안녕하세요. 저는 Sunshine Painters사의 Kelly McDermott입니다. 저희는 오늘 귀하의 부동산 사무실 외벽을 페인트칠할 예정입니다. 하지만 저희의 트럭이 방금 고장이 나서 오늘 아침에 귀하의 건물에 도착하지 못할 것 같습니다."}, {"sp": "M", "en": "Oh, I'm sorry to hear that . . . When might you be able to do the work?", "ko": "아, 유감이네요... 언제 작업을 할 수 있을 것 같으신가요?"}, {"sp": "W", "en": "Well, the mechanic we spoke to said the vehicle will be fixed this evening. So, can we come by tomorrow?", "ko": "음, 저희가 이야기했던 정비사는 오늘 저녁에 차량이 수리될 거라고 했습니다. 그러니 저희가 내일 가도 될까요?"}, {"sp": "M", "en": "That should be fine. I won't be at the office then, though, as I'm showing homes to prospective buyers all day. But my personal assistant Angela Dawson will be around. Once you arrive, she can answer any questions you may have.", "ko": "괜찮을 거예요. 하지만, 저는 하루 종일 예비 구매자들에게 집을 보여주고 있을 것이기 때문에 그때 사무실에 없을 거예요. 그러나 제 개인 비서인 Angela Dawson이 있을 거예요. 도착하시면, 그녀가 당신이 가질 수 있는 질문들에 대해 답변해드릴 거예요."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "W-Am / M-Cn", "audio": "Test08_62-64.mp3", "qs": [{"n": 62, "q": "According to the woman, what will happen on Thursday?", "opts": ["A project will be finalized.", "Some staff will carpool.", "A parade will be held.", "Some lights will be set up."], "ans": 3, "ko": "여자에 따르면, 목요일에 무슨 일이 일어날 것인가?"}, {"n": 63, "q": "Look at the graphic. Where should employees park on Thursday?", "opts": ["Parking Lot A", "Parking Lot B", "Parking Lot C", "Parking Lot D"], "ans": 2, "ko": "시각 자료를 보시오. 직원들은 목요일에 어디에 주차해야 하는가?"}, {"n": 64, "q": "What will workers have to do to receive free parking?", "opts": ["Display a coupon", "Submit transaction records", "Reserve a space", "Adhere to a time limit"], "ans": 1, "ko": "직원들은 무료 주차를 하기 위해 무엇을 해야 하는가?"}], "script": [{"sp": "W", "en": "Charles, Jackson Street is gonna be closed this Thursday so new traffic lights can be installed. So, laboratory workers who use one of the lots on that road will need to park elsewhere. Could you send a memo informing staff?", "ko": "Charles, 새로운 신호등이 설치될 수 있도록 Jackson가가 이번 주 목요일에 폐쇄될 거예요. 그래서 그 길의 주차장 중 하나를 이용하는 연구실 직원들은 다른 곳에 주차해야 할 거예요. 직원들에게 통지하는 회람을 보내주시겠어요?"}, {"sp": "M", "en": "Of course. Are there alternative arrangements for that day?", "ko": "물론이죠. 그날 대안이 되는 계획이 있나요?"}, {"sp": "W", "en": "Yes. Our employees should park in the garage across from Bartow Manufacturing—you know, the one that's next to Pizza Palace.", "ko": "네. 우리 직원들은 Bartow 제조사 건너편에 있는 차고에 주차해야 해요. 있잖아요, Pizza Palace 옆에 있는 거요."}, {"sp": "M", "en": "But won't people be charged $15 to leave their cars there?", "ko": "하지만 사람들이 그곳에 차를 두면 15달러가 부과되지 않나요?"}, {"sp": "W", "en": "Our company will pay for employees to park there. They just have to submit an expense form along with the relevant receipts to be reimbursed.", "ko": "우리 회사가 그곳에 주차하는 직원들에게 비용을 지급할 거예요. 그들은 상환 받기 위해 관련된 영수증과 함께 경비 양식을 제출하기만 하면 돼요."}], "gimg": "hk_t8_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "W-Br / M-Au", "audio": "Test08_65-67.mp3", "qs": [{"n": 65, "q": "What does the woman say she will do this afternoon?", "opts": ["Attend a business event", "Update a schedule", "Become a gym member", "Stop by a clinic"], "ans": 0, "ko": "여자는 오늘 오후에 무엇을 할 것이라고 말하는가?"}, {"n": 66, "q": "Look at the graphic. Which vitamin is the woman lacking?", "opts": ["Vitamin A", "Vitamin B", "Vitamin C", "Vitamin D"], "ans": 2, "ko": "시각 자료를 보시오. 여자는 어떤 비타민이 부족한가?"}, {"n": 67, "q": "What does the man offer the woman?", "opts": ["A medical prescription", "A pamphlet", "A sample", "A membership card"], "ans": 2, "ko": "남자는 여자에게 무엇을 제공하는가?"}], "script": [{"sp": "W", "en": "Thanks for rescheduling my personal training session, Devon. I can't come to the fitness center this afternoon today because I'm representing my company at a trade fair.", "ko": "제 개인 훈련 일정을 변경해주셔서 감사해요, Devon. 제가 무역 박람회에서 저희 회사를 대표할 거라서 오늘 오후에 헬스장에 올 수가 없어요."}, {"sp": "M", "en": "No problem. Should we get started with your workout?", "ko": "괜찮아요. 운동을 시작할까요?"}, {"sp": "W", "en": "Actually, I'd like to ask you about something first. My doctor recommends I take a supplement, and the PulseTrain Multivitamin offers 70 percent of the daily value for the vitamin I'm lacking. Have you heard of that brand before?", "ko": "사실, 먼저 당신에게 물어보고 싶은 게 있어요. 제 의사는 제가 보조 식품을 복용할 것을 권하는데, PulseTrain 종합비타민은 저에게 부족한 비타민의 1일 기준치 중 70퍼센트를 제공해요. 이 브랜드에 대해 이전에 들어 보신 적이 있나요?"}, {"sp": "M", "en": "PulseTrain products are quite good. Um, I have some complimentary multivitamin packages that a PulseTrain representative left with me to hand out to my clients. Why don't you take one?", "ko": "PulseTrain 제품은 상당히 좋아요. 음, 제 고객들에게 나눠주도록 PulseTrain 직원이 남겨둔 무료 종합비타민 상품들이 있어요. 하나 가져가시겠어요?"}], "gimg": "hk_t8_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "M-Cn / W-Am", "audio": "Test08_68-70.mp3", "qs": [{"n": 68, "q": "What will the woman notify the audience about?", "opts": ["A seating shortage", "A technical malfunction", "A miscommunication", "A schedule change"], "ans": 3, "ko": "여자는 청중에게 무엇에 대해 알릴 것인가?"}, {"n": 69, "q": "Look at the graphic. Where will Andrea Parker most likely give a talk?", "opts": ["In Room 101", "In Room 102", "In Room 103", "In Room 104"], "ans": 2, "ko": "시각 자료를 보시오. Andrea Parker는 어디에서 연설을 할 것 같은가?"}, {"n": 70, "q": "Why does the man apologize?", "opts": ["An inaccurate program was printed.", "A team will be short on staff.", "A time slot is no longer available.", "A registration form is missing."], "ans": 1, "ko": "남자는 왜 사과하는가?"}], "script": [{"sp": "M", "en": "Sheryl, a word please? The talk on renewable energy is going to start 20 minutes behind schedule. The speaker texted to say cars are at a standstill on Highway 14.", "ko": "Sheryl, 잠시 이야기 나눌 수 있을까요? 재생 가능한 에너지에 관한 연설이 예정보다 20분 늦게 시작할 거예요. 연사가 문자 메시지를 보냈는데 14번 고속도로에서 차들이 정지해 있다고 해요."}, {"sp": "W", "en": "OK. I'll notify the audience about the change.", "ko": "알았어요. 제가 변동 사항에 대해 청중에게 알릴게요."}, {"sp": "M", "en": "Meanwhile, regarding the keynote lecture, over 200 people signed up to hear it.", "ko": "한편, 기조 연설에 대해서는 200명이 넘는 사람들이 그것을 듣기 위해 등록했어요."}, {"sp": "W", "en": "I'm not surprised. Food waste is an important issue, and Andrea Parker has written a best-selling book on the topic.", "ko": "놀랍지 않네요. 음식물 쓰레기는 중요한 문제이고, Andrea Parker는 그 주제에 대해 베스트셀러를 썼잖아요."}, {"sp": "M", "en": "Oh . . . I almost forgot. Sorry to say, but a valet parking driver called in sick. I know you're overseeing that team as well. Hopefully, you can make things work with one less person.", "ko": "아... 하마터면 잊을 뻔했네요. 미안하지만, 주차 대행 운전사가 아파서 결근한다고 전화했어요. 당신이 그 팀 또한 관리하고 있다는 것을 알아요. 바라건대, 한 명이 부족해도 일을 잘 진행할 수 있으면 좋겠네요."}], "gimg": "hk_t8_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "Cn", "audio": "Test08_71-73.mp3", "qs": [{"n": 71, "q": "What is the radio broadcast mainly about?", "opts": ["A traffic disruption", "A building expansion", "A medical grant", "An education campaign"], "ans": 1, "ko": "라디오 방송은 주로 무엇에 관한 것인가?"}, {"n": 72, "q": "What will happen next week?", "opts": ["A facility will resume operations.", "A press conference will take place.", "An executive position will be filled.", "A monument will be unveiled."], "ans": 0, "ko": "다음 주에 무슨 일이 일어날 것인가?"}, {"n": 73, "q": "What is Roselyn Geddy going to discuss?", "opts": ["Public health issues", "Membership requirements", "Plans for a celebration", "Increases in taxes"], "ans": 2, "ko": "Roselyn Geddy는 무엇을 이야기할 것인가?"}], "script": [{"sp": "S", "en": "Last week on Around Town, we talked about the new monument on Rockport Road. This time we'll focus on the renovations at Bloomington Medical Center. They've been in progress for six months and are now wrapping up. When the center opens its doors again next week, it will be considerably larger—with 25 percent more beds for patients and additional room for diagnostic equipment. I've got Director Roselyn Geddy on the phone right now. She's going to tell us about the ceremony that's been organized to mark the grand reopening.", "ko": "지난주 Around Town에서, 저희는 Rockport가의 새로운 기념물에 대해 이야기했습니다. 이번 시간에 저희는 Bloomington 의료 센터의 보수 공사에 초점을 맞출 것입니다. 이 보수 공사는 6개월 동안 진행되어 왔고, 이제 마무리되고 있습니다. 다음 주에 센터가 다시 문을 열 때, 환자들을 위한 25퍼센트 더 많은 침대와 진단 장비를 위한 추가 공간으로 인해 이것은 상당히 커질 것입니다. 책임자인 Roselyn Geddy가 지금 전화로 연결되어 있습니다. 그녀는 재개장을 축하하기 위해 준비된 기념식에 대해 이야기해줄 것입니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "Au", "audio": "Test08_74-76.mp3", "qs": [{"n": 74, "q": "What did the speaker talk to Ms. Carver about?", "opts": ["Some schedules", "Some research", "Some expectations", "Some concerns"], "ans": 2, "ko": "화자는 Ms. Carver와 무엇에 관해 이야기했는가?"}, {"n": 75, "q": "What will the production focus on?", "opts": ["Safety procedures", "Workplace communication", "Scientific discoveries", "Laboratory equipment"], "ans": 0, "ko": "제작물은 어떤 것에 초점을 맞출 것인가?"}, {"n": 76, "q": "What are the listeners instructed to do next?", "opts": ["Review some educational materials", "Put on a piece of clothing", "Rehearse lines from a script", "Repair some machinery"], "ans": 1, "ko": "청자들은 다음에 무엇을 하도록 안내되는가?"}], "script": [{"sp": "S", "en": "I appreciate everyone coming today to make a laboratory training video for GenTech. I've spoken with Ms. Carver, GenTech's head researcher, about her hopes for the shoot. As chemicals are often used in GenTech's labs, she wants to focus on safety protocols. The video we're producing will demonstrate the correct procedures for dealing with any chemical spills or other laboratory accidents. There are some extra lab coats hanging on the wall. If all of you could please put one on, I'll begin preparing for the shoot.", "ko": "GenTech의 실험실 교육 비디오를 제작하기 위해 오늘 와주신 모든 분들께 감사드립니다. 저는 GenTech의 수석 연구원인 Ms. Carver와 촬영에 대해 그녀가 바라는 것과 관련하여 이야기했습니다. GenTech 실험실에서 화학 물질이 자주 사용되기 때문에, 그녀는 안전 규약에 초점을 맞추기를 원합니다. 우리가 제작하는 비디오는 화학 물질 유출이나 다른 실험실 사고를 처리하는 정확한 절차를 설명할 것입니다. 벽에 여분의 실험실 가운이 걸려 있습니다. 여러분 모두가 하나씩 입으시면, 저는 촬영 준비를 시작하겠습니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test08_77-79.mp3", "qs": [{"n": 77, "q": "Where do the listeners most likely work?", "opts": ["At a financial institution", "At a government agency", "At a computer manufacturer", "At a publishing company"], "ans": 2, "ko": "청자들이 일하는 장소를 묻는 문제이므로, 신분 및 직업과 관련된 표현을 놓치지 않고 듣는다. \"Several government agencies have placed orders with us for laptops.\"라며 여러 정부 기관들이 자신들에게 노트북 컴퓨터를 주문했다고 한 것을 통해 청자들이 일하는 장소가 컴퓨터 제조사임을 알 수 있다. 따라서 정답은 (C) At a computer manufacturer이다."}, {"n": 78, "q": "What does the speaker mean when he says, \"They need the products next week\"?", "opts": ["There will not be much time to prepare.", "A deadline has been pushed forward.", "There will be an expedited shipping fee.", "A miscommunication has been corrected."], "ans": 0, "ko": "화자가 한 말의 의도를 묻는 문제이므로, 질문의 인용어구(They need the products next week)가 언급된 주변을 주의 깊게 듣는다. \"2,200 units of our latest computer models must be shipped out.\"이라며 자신들의 가장 최신 컴퓨터 모델들 2,200대가 발송되어야 한다고 한 뒤, \"They need the products next week, which certainly puts some pressure on us.\"라며 그들은 제품들이 다음 주에 필요하며 이는 분명히 자신들에게 압박을 준다고 했으므로, 준비할 시간이 많지 않을 것임을 알 수 있다. 따라서 정답은 (A) There will not be much time to prepare이다."}, {"n": 79, "q": "What does the speaker hope to do?", "opts": ["Upgrade some software", "Address a client's complaints", "Arrange an initial meeting", "Form a business relationship"], "ans": 3, "ko": "화자가 희망하는 것을 묻는 문제이므로, 질문의 핵심어구(hope to do)와 관련된 내용을 주의 깊게 듣는다. \"my hope is that we'll be able to establish a long-term partnership with the government\"라며 자신들이 정부와 장기적인 협력 관계를 구축할 수 있기를 바란다고 하였다. 따라서 정답은 (D) Form a business relationship이다."}], "script": [{"sp": "M", "en": "To start this meeting, I have some important news. Several government agencies have placed orders with us for laptops. As a result, 2,200 units of our latest computer models must be shipped out. They need the products next week, which certainly puts some pressure on us. However, my hope is that we'll be able to establish a long-term partnership with the government. So, let's all work hard to make sure this process goes as smoothly as possible.", "ko": "회의를 시작하면서, 저는 중요한 뉴스가 있습니다. 여러 정부 기관들이 우리에게 노트북 컴퓨터를 주문했습니다. 그 결과, 우리의 가장 최신 컴퓨터 모델들 2,200대가 발송되어야 합니다. 그들은 제품들이 다음 주에 필요하며, 이는 분명히 우리에게 압박을 줍니다. 하지만, 저는 우리가 정부와 장기적인 협력 관계를 구축할 수 있기를 바랍니다. 그러므로, 이 과정이 반드시 가능한 한 매끄럽게 진행되도록 우리 모두 열심히 일하도록 합시다."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "Br", "audio": "Test08_80-82.mp3", "qs": [{"n": 80, "q": "What is being unveiled?", "opts": ["A community center", "A monument", "A painting", "An orchestra hall"], "ans": 1, "ko": "무엇이 공개되고 있는가? (A) 지역 회관 (B) 기념물 (C) 그림 (D) 오케스트라 홀"}, {"n": 81, "q": "According to the speaker, what did Janice Longoria do?", "opts": ["Trained with a well-known musician", "Volunteered her time", "Gave a speech to a crowd", "Created a piece of art"], "ans": 3, "ko": "화자에 따르면, Janice Longoria는 무엇을 했는가? (A) 잘 알려진 음악가와 훈련했다. (B) 그녀의 시간을 자원하였다. (C) 군중에게 연설을 했다. (D) 예술 작품을 만들었다."}, {"n": 82, "q": "What is mentioned about the city council?", "opts": ["It declared a special holiday.", "It welcomed a new member.", "It covered an expense.", "It made a recommendation."], "ans": 2, "ko": "시의회에 관해 무엇이 언급되는가? (A) 임시 공휴일을 선언했다. (B) 새로운 회원을 환영했다. (C) 비용을 부담했다. (D) 추천을 했다."}], "script": [{"sp": "M", "en": "Thank you all for joining me this evening to pay honor to legendary jazz musician Herb Jean. The statue of Mr. Jean being unveiled was made by sculptor Janice Longoria, who is herself a huge fan of the pianist. While many millions of people around the world have been moved by his music, very few know that he was raised right here in Brighton, England. That's why our city council decided to fund the creation of this incredible artwork. Even though Mr. Jean couldn't join us today due to tour obligations, he has informed us by letter just how grateful he is.", "ko": "전설적인 재즈 음악가인 Herb Jean에게 경의를 표하기 위해 오늘 저녁에 모여주신 모든 분들께 감사드립니다. 공개되는 Mr. Jean의 조각상은 조각가 Janice Longoria에 의해 만들어졌는데, 그녀 자신이 이 피아니스트의 엄청난 팬입니다. 전 세계의 수백만 명의 사람들이 그의 음악에 의해 감동받아왔지만, 그가 바로 여기 영국의 Brighton에서 자랐다는 것을 아는 사람은 거의 없습니다. 그것이 시의회가 이 놀라운 예술품의 제작을 후원하기로 결정한 이유입니다. Mr. Jean이 순회 공연 의무로 인해 오늘 우리와 함께 할 수 없었지만, 그가 정말 얼마나 감사한지 편지로 우리에게 알려왔습니다."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test08_83-85.mp3", "qs": [{"n": 83, "q": "What is being advertised?", "opts": ["An e-book reader", "A portable printer", "An audio device", "A television"], "ans": 2, "ko": "무엇이 광고되고 있는가? (A) 전자책 단말기 (B) 휴대용 프린터 (C) 오디오 장치 (D) 텔레비전"}, {"n": 84, "q": "What does the speaker mean when she says, \"Customers have been pleasantly surprised by that\"?", "opts": ["A standard price is affordable.", "An online service is reliable.", "A policy has received praise.", "A feature is convenient."], "ans": 3, "ko": "화자는 \"고객들은 그것에 기분 좋게 놀랐습니다\"라고 말할 때 무엇을 의도하는가? (A) 표준가격이 알맞다. (B) 온라인 서비스가 믿을 만하다. (C) 정책이 찬사를 받았다. (D) 특징이 편리하다."}, {"n": 85, "q": "According to the speaker, why should listeners visit a store?", "opts": ["To pre-order merchandise", "To request a free upgrade", "To take advantage of a sale", "To test a product"], "ans": 3, "ko": "화자에 따르면, 청자들은 왜 상점에 방문해야 하는가? (A) 상품을 예약 주문하기 위해 (B) 무료 업그레이드를 요청하기 위해 (C) 할인 판매를 이용하기 위해 (D) 제품을 시험해 보기 위해"}], "script": [{"sp": "W", "en": "There's no better way to listen to the music or your favorite podcasts than the Sable Portable Speaker from HomePerfect Electronics. The Sable has wireless connectivity, allowing users to stream content from the Internet without connecting any cables. Moreover, it is an entirely voice-controlled device, meaning you don't have to walk across the room every time you want to change songs or adjust the volume. Customers have been pleasantly surprised by that. So what are you waiting for? Stop by your nearest major electronics retailer to try one out!", "ko": "당신이 음악이나 좋아하는 팟캐스트를 듣는 데 HomePerfect 전자의 Sable 휴대용 스피커보다 더 좋은 방법은 없습니다. Sable은 무선으로 연결할 수 있어서, 사용자들이 어떤 전선을 연결하지 않아도 인터넷으로 컨텐츠를 재생할 수 있도록 해줍니다. 게다가, 이것은 완전히 음성으로 제어할 수 있는 장치인데, 이는 당신이 노래를 변경하거나 음량을 조절하고 싶을 때마다 방안을 걸어 다닐 필요가 없다는 것을 의미합니다. 고객들은 그것에 기분 좋게 놀랐습니다. 그러니 무엇을 기다리고 계신가요? 가장 가까운 대형 전자 제품 판매점에 들르셔서 시험해 보세요!"}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "M-Au", "audio": "Test08_86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker say he will do?", "opts": ["Hand out workshop schedules", "Present a slideshow", "Conduct additional studies", "Explain some posters"], "ans": 1, "ko": "화자는 무엇을 할 것이라고 말하는가? (A) 워크숍 일정을 나누어 준다. (B) 슬라이드 쇼를 발표한다. (C) 추가적인 연구를 실시한다. (D) 몇몇 포스터를 설명한다."}, {"n": 87, "q": "What does the speaker say about Hashtag Goods?", "opts": ["It is famous for its cleaning products.", "It has overseas factories.", "It has hired a new president.", "It is a large retail company."], "ans": 3, "ko": "화자는 Hashtag Goods사에 관해 무엇을 말하는가? (A) 세척제로 유명하다. (B) 해외 공장들을 갖고 있다. (C) 새로운 사장을 고용했다. (D) 대형 소매업체이다."}, {"n": 88, "q": "What is a video about?", "opts": ["International industry trade shows", "Award-winning advertising campaigns", "Marketing techniques from different countries", "Sports teams from around the world"], "ans": 2, "ko": "비디오는 무엇에 관한 것인가? (A) 국제 산업 무역 박람회 (B) 상을 받은 광고 캠페인 (C) 여러 국가들의 마케팅 기법 (D) 전 세계의 스포츠팀"}], "script": [{"sp": "M", "en": "Thank you for attending today's lecture about global sports marketing. My name is Thomas Brast, and I'm going to present a slideshow about a marketing case study I did. The study, which involves the massive athletic apparel chain store Hashtag Goods, focuses on the impact social media advertising has on young adults worldwide. Following that, we'll watch a brief video regarding advertising methods used in various countries. I think you'll find it very informative as well as relevant as it compares practices common here in Canada to those in Egypt and Brazil. Now, let's get started.", "ko": "세계의 스포츠 마케팅에 대한 오늘의 강의에 참석해 주셔서 감사합니다. 제 이름은 Thomas Brast이고, 제가 했던 마케팅 사례 연구에 대한 슬라이드 쇼를 발표할 것입니다. 거대한 운동복 체인점 Hashtag Goods사를 포함하는 이 연구는 전 세계의 젊은이들에게 미치는 소셜 미디어 광고의 효과에 초점을 맞춥니다. 뒤이어, 저희는 다양한 나라들에서 사용되는 광고 방법에 관한 짧은 비디오를 볼 것입니다. 그것은 여기 캐나다에서 흔한 관행들과 이집트와 브라질의 관행들을 비교하기 때문에 여러분이 이것을 적절할 뿐 아니라 매우 유익하다고 생각하실 것 같습니다. 자, 이제 시작하겠습니다."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "W-Am", "audio": "Test08_89-91.mp3", "qs": [{"n": 89, "q": "Who most likely is the listener?", "opts": ["A product designer", "A sales associate", "A travel agent", "A technical worker"], "ans": 3, "ko": "청자는 누구인 것 같은가? (A) 제품 디자이너 (B) 영업 사원 (C) 여행사 직원 (D) 기술자"}, {"n": 90, "q": "What does the speaker ask the listener to do?", "opts": ["Call a manager", "Order a new device", "Reschedule a meeting", "Visit a workspace"], "ans": 3, "ko": "화자는 청자에게 무엇을 해달라고 요청하는가? (A) 관리자에게 전화한다. (B) 새로운 기기를 주문한다. (C) 회의 일정을 변경한다. (D) 업무 공간을 방문한다."}, {"n": 91, "q": "What does the speaker say she must do in Madrid?", "opts": ["Negotiate some contracts", "Deliver a package", "Send meeting details", "Attend a seminar"], "ans": 2, "ko": "화자는 마드리드에서 무엇을 해야 한다고 말하는가? (A) 계약을 성사시킨다. (B) 소포를 배달한다. (C) 회의 세부 사항을 보낸다. (D) 세미나에 참석한다."}], "script": [{"sp": "W", "en": "Hi, Gavin. This is Carla from the product design team. I'm calling because I'm having trouble accessing my work e-mail through the company cell phone I received yesterday. Do you think you could come by my desk sometime today or tomorrow to help me resolve the matter? I'll have to get this done by Thursday morning at the latest since that's when I'll be leaving on a business trip for Madrid. I . . . ah . . . I'll be reporting back to headquarters during my trip about my client meetings, so this situation will have to be dealt with before then.", "ko": "안녕하세요, Gavin. 저는 제품 디자인팀의 Carla입니다. 어제 받은 회사 휴대 전화로 제 업무 이메일에 접속하는 데 어려움을 겪고 있어서 전화를 드립니다. 오늘이나 내일 아무 때나 제 자리로 오셔서 제가 이 문제를 해결하는 것을 도와주실 수 있으신가요? 저는 늦어도 목요일 아침까지는 이걸 해결해야 하는데 그날 마드리드로 출장을 떠나기 때문입니다. 저는… 아… 출장 중 고객과의 회의에 대해 본사에 보고를 할 것이기에, 이 상황이 그 전에 처리되어야 할 것입니다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "Cn", "audio": "Test08_92-94.mp3", "qs": [{"n": 92, "q": "Who are the listeners?", "opts": ["Tour guides", "Museum staff", "Gallery curators", "City officials"], "ans": 0, "ko": "청자들은 누구인가? (A) 여행 가이드 (B) 박물관 직원 (C) 미술관 큐레이터 (D) 시 공무원"}, {"n": 93, "q": "What are listeners instructed to do?", "opts": ["Print out some pamphlets", "Direct guests to a lobby", "Show up at a site early", "Wear a name tag for an event"], "ans": 2, "ko": "청자들은 무엇을 하도록 안내되는가? (A) 책자를 출력한다. (B) 손님들을 로비로 안내한다. (C) 장소에 일찍 나타난다. (D) 이벤트를 위한 명찰을 착용한다."}, {"n": 94, "q": "Why does the speaker say, \"There are over a dozen attractions to visit\"?", "opts": ["To explain a task", "To emphasize a point", "To correct a mistake", "To announce a change"], "ans": 1, "ko": "화자는 왜 \"여기에는 방문할 십여 개가 넘는 명소가 있습니다\"라고 말하는가? (A) 업무를 설명하기 위해 (B) 요점을 강조하기 위해 (C) 실수를 바로잡기 위해 (D) 변경 사항을 알리기 위해"}], "script": [{"sp": "W", "en": "Once again, congratulations on being hired to lead tours for Auckland City Experience. We've come here to Auckland's main square because it's typically where we begin our city tour. Our customers are asked to arrive at least 10 minutes before their walking tour starts, but you'll need to be here 30 minutes early—to answer questions and deal with special requests. This morning, the focus will be on our Heritage Tour, which is very long. There are over a dozen attractions to visit, and they are spread throughout town. Pay close attention as we spend time at each location because this is our most popular route. Oh . . . but first let me hand out the relevant brochures.", "ko": "다시 한번, 오클랜드 도시 경험 관광을 안내하기 위해 고용되신 것을 축하드립니다. 저희는 오클랜드의 주요 광장에 왔는데, 여기가 전형적으로 저희의 시내 관광이 시작되는 곳이기 때문입니다. 저희 고객들은 도보 여행이 시작되기 최소한 10분 전에 도착하도록 요구되지만, 여러분은 질문에 답하고 특별한 요구 사항을 다루기 위해 여기에 30분 일찍 오셔야 할 것입니다. 오늘 아침, 초점은 저희의 문화 유산 관광이 될 것이고, 이것은 매우 오래 걸립니다. 여기에는 방문할 십여 개가 넘는 명소가 있으며, 그것들은 마을 전역에 흩어져 있습니다. 이것이 가장 인기 있는 경로이기 때문에 각 장소에서 시간을 보낼 때 세심한 주의를 기울여 주시기 바랍니다. 아… 그런데 먼저 제가 관련된 안내 책자를 나누어 드리겠습니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "W-Br", "audio": "Test08_95-97.mp3", "qs": [{"n": 95, "q": "What problem does the speaker mention?", "opts": ["A billing statement is inaccurate.", "A Web site recently malfunctioned.", "A piece of apparel was damaged.", "A delivery truck is stuck in traffic."], "ans": 1, "ko": "화자는 어떤 문제를 언급하는가? (A) 청구서가 정확하지 않다. (B) 웹사이트가 최근에 제대로 작동하지 않았다. (C) 의류가 손상되었다. (D) 배송 트럭이 교통 체증에 갇혀 있다."}, {"n": 96, "q": "Look at the graphic. What is the listener's order number?", "opts": ["8832019", "8823901", "8800929", "8811118"], "ans": 2, "ko": "시각 자료를 보시오. 청자의 주문 번호는 무엇인가?"}, {"n": 97, "q": "According to the speaker, what will the listener have to do?", "opts": ["Provide a different address", "Sign for a parcel", "Pay a shipping fee", "Return some merchandise"], "ans": 1, "ko": "화자에 따르면, 청자는 무엇을 해야 할 것인가? (A) 다른 주소를 제공한다. (B) 소포에 서명한다. (C) 배송비를 지불한다. (D) 상품을 반납한다."}], "script": [{"sp": "W", "en": "Good afternoon. This is Iris calling from Hasberry Leather Goods.", "ko": "안녕하세요. 저는 Hasberry Leather Goods사에서 전화드리는 Iris입니다."}, {"sp": "W", "en": "I'm sorry to tell you that our Web site was experiencing technical problems on the day you made your purchase.", "ko": "고객님께서 물건을 구매하시던 날 저희 웹사이트에 기술적인 문제가 있었음을 알려드리게 되어 죄송합니다."}, {"sp": "W", "en": "The handbag you bought is not actually in stock, even though the site indicated otherwise.", "ko": "사이트에는 다르게 나타났지만, 고객님이 구입하신 핸드백은 사실 재고가 없습니다."}, {"sp": "W", "en": "This means that the delivery date will be postponed for one week—the package won't arrive at your address until September 15.", "ko": "이는 배송 일자가 일주일 연기될 것이라는 점을 의미하므로, 물품이 9월 15일이나 되어야 고객님의 주소로 도착할 것입니다."}, {"sp": "W", "en": "And please note that the package will require a signature when it is dropped off at your residence.", "ko": "그리고 물품이 고객님의 댁에 도착할 때 서명이 필요할 거라는 점에 유념해 주십시오."}, {"sp": "W", "en": "We're very sorry for the delay, and thank you for your business.", "ko": "지연이 되어 정말 죄송하며, 저희 회사와 거래해 주셔서 감사합니다."}], "gimg": "hk_t8_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "W-Am", "audio": "Test08_98-100.mp3", "qs": [{"n": 98, "q": "Why is a business temporarily shut down?", "opts": ["An inspection must be conducted.", "A window was damaged in a storm.", "A national holiday is being celebrated.", "A space is being renovated."], "ans": 3, "ko": "업체는 왜 일시적으로 문을 닫았는가? (A) 점검이 시행되어야 한다. (B) 창문이 폭풍으로 훼손되었다. (C) 국경일이 기념되고 있다. (D) 공간이 보수되고 있다."}, {"n": 99, "q": "Look at the graphic. Where does the speaker want to dine?", "opts": ["At Victoria Café", "At Sandwich Shack", "At Angela's Place", "At Lake Street Eatery"], "ans": 2, "ko": "시각 자료를 보시오. 화자는 어디에서 식사하고 싶어 하는가? (A) Victoria Café에서 (B) Sandwich Shack에서 (C) Angela's Place에서 (D) Lake Street Eatery에서"}, {"n": 100, "q": "What does the speaker want to do?", "opts": ["Meet at a coffee shop", "Look up restaurant reviews", "Get together later than planned", "Make reservations in advance"], "ans": 2, "ko": "화자는 무엇을 하고 싶어 하는가? (A) 커피숍에서 만난다. (B) 식당의 후기를 찾아본다. (C) 계획한 것보다 늦게 만난다. (D) 미리 예약을 한다."}], "script": [{"sp": "W", "en": "Mason, it's Debra. I wanna let you know that we have to change our dinner plans.", "ko": "Mason, 저 Debra입니다. 우리의 저녁 식사 계획을 바꿔야 한다는 것을 알려드리고 싶습니다."}, {"sp": "W", "en": "I guess Victoria Café is closed right now for renovations.", "ko": "Victoria Café가 보수로 지금 문을 닫은 것 같습니다."}, {"sp": "W", "en": "It's definitely a shame, but the good news is there're plenty of other options around here too.", "ko": "이는 너무나 안타깝지만, 좋은 소식은 이 주변에 다른 선택권 또한 많다는 것입니다."}, {"sp": "W", "en": "In fact, I've been meaning to try the Italian place that opened up across the street from the movie theater.", "ko": "사실, 영화관 길 건너편에 문을 연 이탈리안 레스토랑에 가보고 싶었습니다."}, {"sp": "W", "en": "I forget the restaurant's name, but I can look it up online and then text you.", "ko": "레스토랑 이름을 잊어버렸는데, 온라인으로 찾아보고 당신에게 문자 하겠습니다."}, {"sp": "W", "en": "Why don't we just meet there instead?", "ko": "대신 그곳에서 만나는 건 어떨까요?"}, {"sp": "W", "en": "Also, let's push back dinner until 6 o'clock too.", "ko": "또한, 저녁 시간도 6시로 미루기로 합시다."}, {"sp": "W", "en": "I'm at Five Spike Coffee right now, and I've still got a few things to finish up for work.", "ko": "저는 지금 Five Spike Coffee에 있는데, 아직 끝내야 할 업무가 조금 남았습니다."}], "gimg": "hk_t8_g98.jpg"}]};
